package com.yxj;

import org.bouncycastle.util.encoders.Hex;

import java.util.Base64;

import java.nio.ByteBuffer;
import java.nio.ByteOrder;

public class Base64Util {
    public static void main(String[] args) {
        String s = "";
        byte[] bytes = Base64.getDecoder().decode(s);

        System.out.println(bytes.length/2);
        System.out.println(Hex.toHexString(bytes));

        // 使用ByteBuffer处理字节数组
        ByteBuffer buffer = ByteBuffer.wrap(bytes);
        buffer.order(ByteOrder.LITTLE_ENDIAN); // 设置字节序为Big Endian，根据你的需要调整

        // 创建一个列表来存储转换后的整数
        int[] integers = new int[(bytes.length + 3) / 4]; // 计算可以容纳多少个整数

        // 转换字节到整数
        for (int i = 0; i < integers.length; i++) {
            short aShort = buffer.getShort();
            int i1 = Short.toUnsignedInt(aShort);
            integers[i] = i1; // 从ByteBuffer中读取一个int（4字节）
        }

        // 输出结果
        for (int num : integers) {
            System.out.println(num);
        }
    }



}
